// monitor_puts.c
#include <stdio.h>
#include <stdint.h>
#include <unistd.h>
#include <dlfcn.h>
#include <x86intrin.h>

#define CACHE_HIT_THRESHOLD 80

volatile char *target_addr;

uint64_t measure_access(volatile char *addr) {
    uint64_t start, end;
    _mm_mfence();
    start = __rdtsc();
    _mm_lfence();
    volatile char tmp = *addr;
    _mm_lfence();
    end = __rdtsc();
    _mm_mfence();
    return end - start;
}

int main() {
    // 获取puts函数地址
    void *handle = dlopen("libc.so.6", RTLD_LAZY);
    if (!handle) {
        fprintf(stderr, "dlopen failed\n");
        return 1;
    }
    void *puts_addr = dlsym(handle, "puts");
    if (!puts_addr) {
        fprintf(stderr, "dlsym failed\n");
        return 1;
    }
    target_addr = (volatile char*)puts_addr;
    printf("Monitoring puts at %p\n", target_addr);

    // 监控循环
    while (1) {
        // Flush
        _mm_clflush(target_addr);
        _mm_mfence();
        // 等待（例如100微秒）
        usleep(100);
        // Reload
        uint64_t time = measure_access(target_addr);
        if (time < CACHE_HIT_THRESHOLD) {
            printf("HIT: puts was called!\n");
        }
        // 控制输出频率
        usleep(1000);
    }
    dlclose(handle);
    return 0;
}

