import subprocess
import threading
import time

# 启动监控进程
monitor = subprocess.Popen(['./monitor'], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)

# 启动受害者进程（例如一个循环调用puts的程序）
