常量时间编程是一种防御侧信道攻击（特别是时序攻击）的技术，确保代码执行时间不依赖于秘密数据。核心原则：避免条件分支（如if/else）和可变循环次数依赖于秘密；使用位运算和算术运算代替；确保内存访问模式不依赖于秘密（如避免使用秘密作为数组索引）。常见应用包括密码学中的比较、内存复制、查表等。

以下C代码示例实现常量时间字符串比较和常量时间内存访问（使用掩码）。

c
#include <stdint.h>
#include <string.h>

// 常量时间比较两个固定长度缓冲区
int constant_time_memcmp(const void *a, const void *b, size_t len) {
    const uint8_t *pa = (const uint8_t*)a;
    const uint8_t *pb = (const uint8_t*)b;
    uint8_t result = 0;
    for (size_t i = 0; i < len; i++) {
        result |= pa[i] ^ pb[i];  // 异或累积
    }
    // 如果result为0则返回0，否则返回1
    // 使用位运算避免分支
    return (result != 0);  // 注意：!= 可能被编译器优化为分支，应使用位运算
    // 更安全的写法：return (0 - (uint8_t)(result != 0)); 但依赖编译器
}

// 常量时间选择：根据条件返回a或b（条件为0或1）
uint8_t constant_time_select(uint8_t condition, uint8_t a, uint8_t b) {
    // condition必须是0或1
    uint8_t mask = (uint8_t)(0 - condition);  // 0->0x00, 1->0xFF
    return (a & mask) | (b & ~mask);
}

// 常量时间内存访问：使用掩码避免数组越界
// 假设我们有一个表table[256]，想根据秘密索引访问，但索引可能越界
uint8_t constant_time_table_lookup(const uint8_t *table, size_t index, size_t table_size) {
    uint8_t result = 0;
    for (size_t i = 0; i < table_size; i++) {
        // 如果i==index，则选择table[i]，否则选择0
        uint8_t mask = (uint8_t)(0 - (i == index));  // 注意：==可能产生分支，应使用位运算
        // 更安全的写法：使用异或和减法
        // 这里简化
        result |= table[i] & mask;
    }
    return result;
}

// 更好的常量时间查表：使用位切片或预计算
// 但上述方法循环次数固定，且不依赖index值，但依赖table_size

int main() {
    uint8_t secret[4] = {0x12, 0x34, 0x56, 0x78};
    uint8_t input[4] = {0x12, 0x34, 0x56, 0x79};
    int cmp = constant_time_memcmp(secret, input, 4);
    // cmp非零表示不相等
    return 0;
}


注意：编译器优化可能破坏常量时间属性（如将`!=`优化为分支）。建议使用编译器内置函数（如`__builtin_constant_p`）或内联汇编。现代密码库如libsodium提供了`crypto_verify_16`等常量时间函数。此外，缓存侧信道防御需要确保内存访问模式不依赖秘密，例如使用`_mm_clflush`和`_mm_lfence`指令，或使用硬件特性如Intel SGX。

perf是Linux性能分析工具，可通过`perf_event_open`系统调用访问硬件性能计数器，如缓存未命中（cache-misses）、指令周期等。在侧信道攻击中，攻击者可以利用perf监控受害者的缓存行为，例如通过测量缓存未命中次数推断受害者是否访问了特定内存。但perf需要root权限或`perf_event_paranoid`设置。以下POC演示如何使用perf监控一个进程的L1缓存未命中，并关联到特定内存访问。

c
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/perf_event.h>
#include <asm/unistd.h>

static long perf_event_open(struct perf_event_attr *hw_event, pid_t pid,
                            int cpu, int group_fd, unsigned long flags) {
    return syscall(__NR_perf_event_open, hw_event, pid, cpu, group_fd, flags);
}

int main() {
    struct perf_event_attr pe;
    memset(&pe, 0, sizeof(pe));
    pe.type = PERF_TYPE_HARDWARE;
    pe.size = sizeof(pe);
    pe.config = PERF_COUNT_HW_CACHE_MISSES;  // 缓存未命中
    pe.disabled = 1;
    pe.exclude_kernel = 1;
    pe.exclude_hv = 1;

    int fd = perf_event_open(&pe, 0, -1, -1, 0);
    if (fd == -1) {
        perror("perf_event_open");
        exit(EXIT_FAILURE);
    }

    // 启动计数
    ioctl(fd, PERF_EVENT_IOC_RESET, 0);
    ioctl(fd, PERF_EVENT_IOC_ENABLE, 0);

    // 模拟受害者操作：访问一个数组
    volatile uint8_t *buffer = malloc(1024 * 1024);
    memset((void*)buffer, 0, 1024 * 1024);
    for (int i = 0; i < 1000; i++) {
        volatile uint8_t tmp = buffer[i * 64];  // 按缓存行访问
    }

    // 停止计数
    ioctl(fd, PERF_EVENT_IOC_DISABLE, 0);

    long long count;
    read(fd, &count, sizeof(count));
    printf("Cache misses: %lld\n", count);

    free((void*)buffer);
    close(fd);
    return 0;
}


该代码监控当前进程的缓存未命中次数。在侧信道攻击中，攻击者可以：1) 作为独立进程监控受害者进程（通过指定pid）；2) 利用perf的采样功能记录指令地址与缓存未命中的关联；3) 结合Flush+Reload，通过perf测量Reload时间差异。注意：perf事件需要精确的硬件支持，且高精度测量可能受上下文切换影响。防御方法包括限制perf访问（设置`perf_event_paranoid=3`）或使用硬件计数器随机化。

Spectre v1（CVE-2017-5753）利用现代CPU的分支预测和乱序执行机制。攻击者训练分支预测器使其在后续执行中错误预测，导致CPU在检查条件之前就执行了越界访问，并将数据加载到缓存中。即使后续检查失败并回滚架构状态，缓存状态不会回滚，攻击者可以通过Flush+Reload等侧信道提取数据。

核心原理：
1. 受害者代码中存在一个边界检查（如`if (x < array1_size)`），之后使用`x`索引访问`array1`，然后根据`array1[x]`的值访问`array2`。
2. 攻击者先训练分支预测器，使其认为`x`总是小于`array1_size`（例如多次传入合法索引）。
3. 然后传入一个越界索引（如`x = secret_offset`），此时CPU预测分支为真，乱序执行读取`array1[secret_offset]`（可能为内核内存），然后根据该值访问`array2[data * 256]`，将数据带入缓存。
4. 虽然最终分支检查失败，CPU回滚，但缓存中留下了`array2`的访问痕迹。
5. 攻击者通过Flush+Reload探测`array2`的各个缓存行，确定哪个偏移被访问，从而恢复秘密字节。

以下是一个读取内核内存的POC（用户态利用，假设存在漏洞的内核模块或eBPF程序）：
