        }

        // Reload检测
        uint64_t min_time = UINT64_MAX;
        size_t min_idx = 0;
        for (size_t i = 0; i < ARRAY_SIZE; i++) {
            uint64_t t = measure_time(&probe_array[i * CACHE_LINE_SIZE]);
            if (t < min_time) {
                min_time = t;
                min_idx = i;
            }
        }
