uint64_t measure_access(volatile int *addr) {
    uint64_t start, end;
    unsigned int aux;
    start = __rdtscp(&aux);
    // 强制读取，避免编译器优化
    volatile int tmp = *addr;
    end = __rdtscp(&aux);
    return end - start;
}

int main() {
    // 步骤1: Flush
    _mm_clflush(&shared_variable);
    _mm_mfence();

    // 步骤2: 等待受害者执行
    victim_function();

